using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;
using System;
using System.Linq;

public class EventBookingSystemContext : DbContext {
    public virtual DbSet<Event> Events { get; set; }
    //other dbsets if any
}

public class Event 
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    //other fields
}

public async Task<bool> PurchaseTickets(int eventId, int numberOfTickets)
{ 
    using (var context = new EventBookingSystemContext())
    {
        var @event = await context.Events.FindAsync(eventId);
        
        if(@event == null || @event.AvailableSeats < numberOfTickets) 
            return false; // event not found or insufficient seats
    
        @event.AvailableSeats -= numberOfTickets;
            
        await context.SaveChangesAsync();   
    }  
        
    return true; 
}